const { regular, bold, icons } = await loadFonts();
    const { name, socialMedia, logo, phone } = brandData;
    const scale = getScale(width, height);

    // 1. Bottom Drawer
    const drawerHeight = 250 * scale;
    const paint = Skia.Paint();
    paint.setColor(Skia.Color('white'));
    canvas.drawRect({ x: 0, y: height - drawerHeight, width, height: drawerHeight }, paint);

    // 2. Brand Name
    paint.setColor(Skia.Color('black'));
    const nameFont = bold;
    nameFont.setSize(50 * scale);
    drawTextLeft(canvas, name, 50 * scale, height - drawerHeight + (80 * scale), nameFont, paint, width - (40 * scale));

    // 3. Social Icons
    const iconSize = 40 * scale;
    const infoFont = regular;
    infoFont.setSize(25 * scale);
    let currentX = 50 * scale;
    const startY = height - drawerHeight + (150 * scale);
    const gap = 30 * scale;

    const socials = [
        { icon: 'logo-instagram', value: socialMedia?.instagram, label: 'Insta' },
        { icon: 'logo-tiktok', value: socialMedia?.tiktok, label: 'TikTok' },
        { icon: 'logo-whatsapp', value: phone, label: 'WhatsApp' },
    ];

    socials.forEach(s => {
        if (s.value) {
            // Draw Icon
            paint.setColor(Skia.Color('black'));
            drawIcon(canvas, s.icon, currentX, startY, iconSize, paint, icons);

            // Draw Handle
            const textX = currentX + iconSize + (10 * scale);
            const displayVal = s.label === 'WhatsApp' ? s.value : `@${s.value.replace(/^@/, '')}`; // Ensure @ for handles
            canvas.drawText(displayVal, textX, startY + iconSize - (5 * scale), paint, infoFont);

            // Move X
            const textW = infoFont.getTextWidth(displayVal);
            currentX += iconSize + (10 * scale) + textW + gap;
        }
    });

    // Logo (Floating above drawer right)
    if (logo) {
        const logoSize = 160 * scale;
        const { width: logoW, height: logoH } = getLogoDimensions(logo);
        const aspectRatio = logoH / logoW;

    canvas.save();
    const _clip = Skia.Path.Make();
    _clip.addRRect(Skia.RRectXY({x: width - logoSize - (50 * scale), y: height - drawerHeight - (logoSize * aspectRatio / 2), width: logoSize, height: logoSize * aspectRatio}, 15 * scale, 15 * scale));
    canvas.clipPath(_clip, 1, true);
    drawLogo(canvas, logo, width - logoSize - (50 * scale), height - drawerHeight - (logoSize * aspectRatio / 2), logoSize, logoSize * aspectRatio)
    canvas.restore();;
    }

    return ["name", "socialMedia", "phone", "logoUri"];

